package org.eclipse.rdf4j.query.algebra.evaluation.sketch;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.LinkedHashSet;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.Set;

import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.BindingSetAssignment;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.BindingUniverse;
import org.eclipse.rdf4j.query.impl.MapBindingSet;
import org.junit.jupiter.api.Test;

class QueryLocalFiniteRelationTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void bindingSetAssignmentRelationPreservesArityIdsAndDuplicateMultiplicity() {
		BindingUniverse universe = BindingUniverse.create();
		BindingSetAssignment assignment = values("branchName", "branch",
				row("branchName", "urn:name:a", "branch", "urn:branch:a"),
				row("branchName", "urn:name:a", "branch", "urn:branch:a"),
				row("branchName", "urn:name:b", "branch", "urn:branch:b"));

		QueryLocalFiniteRelation relation = QueryLocalFiniteRelation.from(assignment, universe,
				valueIds("urn:name:a", 11L, "urn:branch:a", 21L, "urn:name:b", 12L, "urn:branch:b", 22L))
				.orElseThrow();

		assertEquals(List.of("branchName", "branch"), relation.bindingNames());
		assertEquals(2, relation.arity());
		assertEquals(3L, relation.rowCount());
		assertEquals(2, relation.distinctRowCount());
		assertEquals(2, relation.duplicateMultiplicity(List.of(11L, 21L)));
		assertEquals(1, relation.duplicateMultiplicity(List.of(12L, 22L)));
		assertEquals(Set.of(11L, 12L), relation.valueIds("branchName"));
	}

	@Test
	void unsupportedValuesRejectCleanly() {
		BindingUniverse universe = BindingUniverse.create();
		BindingSetAssignment assignment = values("x", row("x", "urn:unsupported"));

		Optional<QueryLocalFiniteRelation> relation = QueryLocalFiniteRelation.from(assignment, universe, value -> -1L);

		assertTrue(relation.isEmpty());
	}

	@Test
	void virtualSketchFactorIsImmutableAndCarriesRelationMask() {
		BindingUniverse universe = BindingUniverse.create();
		BindingSetAssignment assignment = values("x", row("x", "urn:x:1"), row("x", "urn:x:2"));
		QueryLocalFiniteRelation relation = QueryLocalFiniteRelation.from(assignment, universe,
				valueIds("urn:x:1", 1L, "urn:x:2", 2L)).orElseThrow();

		VirtualSketchFactor factor = VirtualSketchFactor.from("finite:x", relation);

		assertEquals("finite:x", factor.id());
		assertEquals(2L, factor.rowCount());
		assertEquals(universe.maskOf(Set.of("x")), factor.bindingMask());
		assertEquals(Set.of(1L, 2L), factor.valueIds("x"));
	}

	private static BindingSetAssignment values(String bindingName, MapBindingSet... rows) {
		return values(List.of(bindingName), rows);
	}

	private static BindingSetAssignment values(String firstBindingName, String secondBindingName,
			MapBindingSet... rows) {
		return values(List.of(firstBindingName, secondBindingName), rows);
	}

	private static BindingSetAssignment values(List<String> bindingNames, MapBindingSet... rows) {
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingNames(new LinkedHashSet<>(bindingNames));
		assignment.setBindingSets(List.of(rows));
		return assignment;
	}

	private static MapBindingSet row(String name, String iri) {
		MapBindingSet row = new MapBindingSet();
		row.addBinding(name, VF.createIRI(iri));
		return row;
	}

	private static MapBindingSet row(String firstName, String firstIri, String secondName, String secondIri) {
		MapBindingSet row = row(firstName, firstIri);
		row.addBinding(secondName, VF.createIRI(secondIri));
		return row;
	}

	private static QueryLocalFiniteRelation.ValueIdLookup valueIds(Object... pairs) {
		Map<String, Long> values = java.util.stream.IntStream.range(0, pairs.length / 2)
				.boxed()
				.collect(java.util.stream.Collectors.toUnmodifiableMap(i -> (String) pairs[i * 2],
						i -> (Long) pairs[i * 2 + 1]));
		return value -> values.getOrDefault(value.stringValue(), -1L);
	}
}
